import BaseSpotterApiSdk from '../../utils/base-api-sdk';
import {getI18nLanguageRequestPayload} from './i18n.request';
import {AbstractSpotterI18nApiSdk} from './i18n.abstract';
import {DOMAIN_URL} from '../../../const';

/**
 * SpotterI18nApiSdk
 * i18n SDK
 */
export class SpotterI18nApiSdk extends BaseSpotterApiSdk implements AbstractSpotterI18nApiSdk {
    constructor(...baseApiSdkParams: ConstructorParameters<typeof BaseSpotterApiSdk>) {
        super(...baseApiSdkParams);
    }

    /**
     * 获取国际化数据
     * @param data
     */
    async getLanguageFile(data: getI18nLanguageRequestPayload) {
        const {project, component, language, domainUrl} = data
        return this.httpClient.request<object>({
            method: 'get',
            // 如果 domainUrl 不存在，回退到常量
            baseURL: domainUrl || DOMAIN_URL,
            // 如何 language 不存在，回退到 zh_Hans
            url: `/api/translations/${project}/${component}/${
                // zh_Hans to zh映射
                language === 'zh' ? 'zh_Hans' : (language || 'zh_Hans')
            }/file/`,
            headers: {
                'Content-Type': 'application/json',
                // token这里直接写死
                Authorization: 'Token wlu_xRmTEHTCLVlpGhYunVeyFm4kO7AORbHUcZfv',
                'Cache-Control': 'no-cache'
            },
        });
    }
}
